function ctEsc(s){return String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
function ctLane(q){const x=String(q||'').trim().toLowerCase();return CALITREE_LANES.find(l=>l[0]===x)||CALITREE_LANES.find(l=>l[1].toLowerCase()===x)||CALITREE_LANES[0]}
const CALITREE_DISCLAIMER='Educational news and research only. Not medical advice, legal advice, investment advice, diagnosis, treatment, or product endorsement.';
const CT_AUDIENCE='Cannabis consumers, medical cannabis patients, dispensary workers, cannabis business owners, regulators, caregivers, and curious readers.';
const CT_TPL={cannabis_top_stories:{angle:'Cannabis news is most useful when it helps the public understand what changed, why it matters, and where the source information comes from.',visual:'a clean cannabis news desk visual, public-interest news cards, subtle cannabis leaf iconography, source links, headlines, and a modern editorial layout',mood:'curious, informed, balanced, public-interest news tone',question:'What cannabis stories do you think deserve more clear, source-backed coverage?',avoid:'stoner stereotypes, product endorsement, sensational headlines, cluttered weed-leaf graphics'},medical_research:{angle:'Cannabis research should be explained carefully, in plain language, without turning early research into medical advice or product claims.',visual:'a calm medical research visual with lab notes, public research papers, abstract cannabinoid science elements, and a trustworthy healthcare-news composition',mood:'careful, evidence-aware, calm, trustworthy',question:'How should cannabis research be explained to the public without overstating what studies show?',avoid:'miracle-cure imagery, doctors recommending cannabis, patient treatment scenes, exaggerated medical claims'},policy_law:{angle:'Cannabis policy changes can affect consumers, patients, businesses, regulators, workers, and local communities in different ways.',visual:'a civic cannabis policy news graphic with government documents, state capitol imagery, regulation files, a clean legal-news layout, and subtle cannabis policy symbolism',mood:'civic, serious, clear, nonpartisan, explanatory',question:'What cannabis policy changes do you think the public needs explained more clearly?',avoid:'partisan attack imagery, protest chaos, legal advice, arrest scenes, sensational enforcement visuals'},state_regulators:{angle:'State regulator pages help the public track licensing, compliance, enforcement, recalls, official notices, and rule updates from primary sources.',visual:'a state cannabis regulator dashboard concept with official documents, licensing forms, compliance checklists, map pins, and a clean government-services design',mood:'official, practical, trustworthy, public-service oriented',question:'Should state cannabis regulator information be easier for the public to search and understand?',avoid:'fake government seals, legal advice, enforcement panic, product promotion, cluttered bureaucracy visuals'},safety_recalls:{angle:'Public cannabis safety information should be easier to find, understand, and share without creating panic or unsupported claims.',visual:'a cannabis public safety notice graphic with a California-style alert board, recall notice cards, caution design elements, clean official-looking documents, and a calm news layout',mood:'calm urgency, trustworthy, informative, public-safety focused',question:'Do you think cannabis safety alerts should be easier for consumers and retailers to find?',avoid:'panic imagery, contamination closeups, gore, fake product names, cannabis use imagery, fear-based design'},ai_cannabis:{angle:'AI and automation may change cannabis compliance, research, retail operations, media, education, and customer support, but the public still needs source-backed context.',visual:'a modern AI cannabis operations graphic with data dashboards, compliance workflows, dispensary technology, neural network patterns, and subtle cannabis industry context',mood:'innovative, clean, thoughtful, future-facing, practical',question:'Where do you think AI could be most useful or most risky in the cannabis industry?',avoid:'chaotic sci-fi imagery, robot smoking cannabis, hype bubbles, unsupported technology claims, product endorsement'},business_industry:{angle:'Cannabis business news is most useful when it explains what market, retail, licensing, compliance, and operator developments could mean without giving investment advice.',visual:'a cannabis business news visual with dispensary retail counters, supply chain documents, market charts, storefront silhouettes, and a polished business-news composition',mood:'professional, market-aware, practical, non-hype',question:'What cannabis business trends do you think deserve more transparent coverage?',avoid:'get-rich imagery, stock-buy signals, product advertising, luxury hype, investment advice visuals'},cbd_thc_science:{angle:'CBD, THC, and cannabinoid science need careful public education that separates research, regulation, safety information, and product claims.',visual:'a clean cannabinoid science explainer graphic with molecular-style abstract elements, CBD and THC labels, research notes, and a calm educational layout',mood:'scientific, educational, careful, accessible',question:'What do you think people most misunderstand about CBD, THC, or cannabinoids?',avoid:'product claims, miracle-cure visuals, dosage advice, intoxication imagery, supplement advertising'}};
function ctTpl(lane,label){return CT_TPL[lane]||CT_TPL[label]||CT_TPL.cannabis_top_stories}
function ctOverlay(label){const x=String(label||'');if(/Safety/i.test(x))return 'Cannabis Safety Notices';if(/Medical/i.test(x))return 'Cannabis Research Update';if(/Policy|Law/i.test(x))return 'Cannabis Policy Watch';if(/Regulator/i.test(x))return 'State Cannabis Updates';if(/AI/i.test(x))return 'AI + Cannabis';if(/Business/i.test(x))return 'Cannabis Business Brief';if(/CBD|THC/i.test(x))return 'CBD / THC Science';return 'Cannabis News Brief'}
function ctSource(r,label){return `SOURCE CARD\nTitle: ${r.title||'Calitree Review source'}\nURL: ${r.url||''}\nCategory: ${label}\nSource type: ${r.source_type||'public source'}\nSearch context: ${r.first_query||''}`}
function ctPostPrompt(r,label,lane){const t=ctTpl(lane,label);return `You are writing for Calitree Review, a cannabis news and medical information Facebook page with a large public audience.\n\nYour task is to create a high-quality Facebook post using the source card below.\n\n${ctSource(r,label)}\n\nAUDIENCE\n${CT_AUDIENCE}\n\nANGLE\n${t.angle}\n\nWRITING GOAL\nCreate a clear, useful, source-backed Facebook post that helps readers understand why this source matters. The post should sound informed, human, and discussion-friendly.\n\nSTRICT RULES\n- Do not recommend cannabis use.\n- Do not give medical advice, legal advice, investment advice, diagnosis, treatment, dosing, or product recommendations.\n- Do not claim the source says something unless it is clearly supported by the source card or source page.\n- Do not invent recall details, medical outcomes, legal changes, enforcement actions, study conclusions, company claims, or product names.\n- Do not use fear-based, sensational, or clickbait language.\n- Keep the tone educational, neutral, useful, and source-backed.\n\nOUTPUT FORMAT\n1. Write one Facebook post, 120 to 220 words.\n2. Start with a strong but responsible hook.\n3. Explain why the source matters in plain language.\n4. Include the source link.\n5. End with this discussion question:\n${t.question}\n6. End with this disclaimer exactly:\n${CALITREE_DISCLAIMER}\n\nOptional: after the post, include 3 short headline alternatives.`}
function ctImagePrompt(r,label,lane){const t=ctTpl(lane,label);return `Create a high-engagement Facebook image for a cannabis news and public education page.\n\n${ctSource(r,label)}\n\nIMAGE GOAL\nCreate a scroll-stopping but responsible image that helps people understand the topic visually without making unsupported claims.\n\nVISUAL DIRECTION\n${t.visual}\n\nMOOD\n${t.mood}\n\nSTYLE\nClean editorial news graphic, modern social media design, polished, professional, high contrast, readable, trustworthy, public-interest tone.\n\nCOMPOSITION\n- Format: 1:1 square or 4:5 vertical Facebook feed image.\n- One strong focal point.\n- Minimal text overlay.\n- Clear hierarchy.\n- Works on mobile.\n- Use visual symbolism, not literal claims.\n\nOPTIONAL TEXT OVERLAY\n${ctOverlay(label)}\n\nAVOID\n${t.avoid}\n- cannabis smoking or consumption\n- product endorsement\n- fake logos or fake official seals\n- excessive text\n- sensationalism\n- medical, legal, or investment claims`}
function ctVideoPrompt(r,label,lane){const t=ctTpl(lane,label);return `Create a short vertical social video concept for a cannabis news and public education page.\n\n${ctSource(r,label)}\n\nVIDEO GOAL\nCreate a 20 to 30 second source-backed social video that explains why this source matters in a clear, calm, engaging way.\n\nFORMAT\n- Vertical 9:16\n- Designed for Facebook Reels, Instagram Reels, TikTok, or YouTube Shorts\n- Clean captions\n- Modern editorial motion graphics\n- No voiceover required, but include optional voiceover text\n\nVISUAL DIRECTION\n${t.visual}\n\nMOOD\n${t.mood}\n\nSCENE STRUCTURE\nScene 1: Strong responsible hook based on the category.\nScene 2: Show the source/topic visually.\nScene 3: Explain why this matters to consumers, patients, businesses, regulators, or caregivers.\nScene 4: Mention that the information should be checked through the original source.\nScene 5: End with this discussion question:\n${t.question}\n\nON-SCREEN TEXT RULES\n- Keep text short.\n- Use plain language.\n- Do not make unsupported claims.\n- Do not imply medical, legal, or investment advice.\n\nAVOID\n${t.avoid}\n- cannabis use imagery\n- product promotion\n- sensational fear visuals\n- unsupported claims\n- fake official branding`}
function ctMusicPrompt(r,label,lane){const t=ctTpl(lane,label);return `Create a short instrumental music cue for a cannabis news and public education video.\n\n${ctSource(r,label)}\n\nMUSIC GOAL\nCreate background music that supports a short educational social video without distracting from the message.\n\nMOOD\n${t.mood}\n\nSTYLE\nModern, clean, social-video friendly, polished, subtle, professional.\n\nDURATION\n20 to 30 seconds.\n\nENERGY\nMedium-low to medium. Engaging but not aggressive.\n\nINSTRUMENTATION\nUse subtle percussion, light bass pulse, soft synth or organic texture, and a clean modern rhythm.\n\nAVOID\n${t.avoid}\n- party vibes\n- psychedelic drug-culture clichés\n- aggressive drops\n- anything that feels like a product commercial\n- anything that suggests cannabis use or intoxication\n- lyrics making medical, legal, product, or investment claims`}
function ctPrompt(r,label){return ctPostPrompt(r,label,r.capture_type)}
function ctDraft(r,label){return ctPrompt(r,label)}
