function ctIntent(m,t){const forced=ctTopic(t);m=String(m||'').toLowerCase();if(forced&&!m)return ctLane(forced);if(/recall|safety|warning|contamination|advisory/.test(m))return ctLane('safety_recalls');if(/policy|law|regulation|fda|dea|legalization|legislation/.test(m))return ctLane('policy_law');if(/medical|research|study|nih|pubmed|clinical|patient/.test(m))return ctLane('medical_research');if(/\bai\b|automation|machine learning|artificial intelligence/.test(m))return ctLane('ai_cannabis');if(/business|market|dispensary|brand|retail|industry/.test(m))return ctLane('business_industry');if(/cbd|thc|cannabinoid|cannabinoids/.test(m))return ctLane('cbd_thc_science');if(/state|regulator|licensing|compliance|department|board/.test(m))return ctLane('state_regulators');return ctLane(forced||'cannabis_top_stories')}
function ctFallbackRows(lane){return (CALITREE_FALLBACK[lane[0]]||CALITREE_FALLBACK.cannabis_top_stories).map(x=>({id:x[0],title:x[1],url:x[2],source_type:x[3],capture_type:lane[0],first_query:x[4],last_action:'seeded_fallback',last_seen_at:nowIso(),created_at:nowIso(),fallback:true}))}
function ctUniq(rows){const out=[],seen=new Set();for(const r of rows||[]){const k=r.url||r.id;if(!k||seen.has(k))continue;seen.add(k);out.push(r)}return out}
async function calitreeRefreshFeeds(env,opts={}){await schema(env);const perFeedLimit=Math.min(Number(opts.limit||6),20);const results=await Promise.allSettled(CALITREE_LIVE_FEEDS.map(async feed=>{const parsed=await inspectFeed({url:feed.url,limit:perFeedLimit});if(!parsed.ok)return{feed:feed.id,title:feed.title,ok:false,error:parsed.error||'fetch_failed'};let upserted=0;for(const item of (parsed.items||[])){const itemUrl=item.url||item.guid;if(!itemUrl)continue;const summary=(item.summary||'').slice(0,300);if(feed.filter&&feed.filter.length){const hay=((item.title||'')+' '+summary).toLowerCase();if(!feed.filter.some(k=>hay.includes(k.toLowerCase())))continue}await upsertIndexItem(env,{url:itemUrl,title:item.title||feed.title,source_type:feed.source_type,capture_type:feed.lane,first_query:(feed.keywords||feed.title)+' '+summary,published_date:item.date,summary},feed.title,'capture');upserted++}return{feed:feed.id,title:feed.title,ok:true,items_seen:(parsed.items||[]).length,rows_upserted:upserted}}));const normalized=results.map((r,i)=>r.status==='fulfilled'?r.value:{feed:CALITREE_LIVE_FEEDS[i].id,title:CALITREE_LIVE_FEEDS[i].title,ok:false,error:String(r.reason&&r.reason.message||r.reason)});const totalUpserted=normalized.reduce((s,r)=>s+(r.rows_upserted||0),0);const totalErrors=normalized.filter(r=>!r.ok).length;const rcpt=await saveReceipt(env,receipt('calitree_live_feed_refresh',{feed_count:CALITREE_LIVE_FEEDS.length,total_upserted:totalUpserted,total_errors:totalErrors,results:normalized}));return{ok:true,feed_count:CALITREE_LIVE_FEEDS.length,total_upserted:totalUpserted,total_errors:totalErrors,results:normalized,refresh_receipt:rcpt,policy:POLICY}}
const CALITREE_ASSISTANT_TOOLS=[{type:'function',function:{name:'search_calitree',description:'Search the live Calitree index of real cannabis news articles, scientific findings, SEC filings, financial/stock news, and podcast episodes. Always use this before answering questions about news, science, finance, SEC filings, podcasts, sources, or what is new or related - never invent headlines. Keep keyword SHORT (1-3 words, e.g. a company name or single topic) - longer phrases match poorly.',parameters:{type:'object',properties:{lane:{type:'string',description:'Optional category filter: '+CALITREE_LANES.map(l=>l[0]).join(', ')},keyword:{type:'string',description:'Optional SHORT keyword(s), 1-3 words max, e.g. a company name or single topic word'},source_type:{type:'string',description:"Optional exact source filter, e.g. 'sec_filing' for SEC filings, 'financial_news' for stock news, 'podcast_feed' for podcasts, 'scientific_feed' for science, 'crime_press_release', 'opinion_research'"},limit:{type:'number',description:'Max results, default 8, max 30'}},required:[]}}},{type:'function',function:{name:'list_lanes',description:'List the available Calitree categories the user can browse or ask about.',parameters:{type:'object',properties:{}}}},{type:'function',function:{name:'get_metrics',description:'Get the latest stored economic/financial metrics (e.g. consumer price index, retail sales) for broader market context. Returns a not-configured message if no data is available yet.',parameters:{type:'object',properties:{}}}},{type:'function',function:{name:'search_cannabis_genetics',description:'Search the live cannabis strain genetics/lineage database (9,500+ strains from a 2017 snapshot dataset). Use this for any question about a specific strain, its cannabinoid profile (THC/CBD/CBN/CBG), its breeder, or its parent/cross lineage. Pass a strain name to search, or a strain_id with tree=true to get its full ancestry tree.',parameters:{type:'object',properties:{strain_name:{type:'string',description:'Strain name to search for, e.g. "Blue Dream" or "OG Kush"'},strain_id:{type:'string',description:'Exact strain ID if already known, to get full detail and lineage instead of searching by name'},tree:{type:'boolean',description:'If true and strain_id is given, also return the full ancestry tree up to 5 generations'},limit:{type:'number',description:'Max search results, default 8, max 20'}},required:[]}}},{type:'function',function:{name:'get_crime_trend',description:'Get aggregate FBI/CDE crime trend data (count and rate per 100k) for a US state and offense type over a year range. This is general public-safety statistical data, NOT cannabis-specific crime data - never imply cannabis caused, increased, decreased, or prevented any crime trend.',parameters:{type:'object',properties:{state:{type:'string',description:'Two-letter state code, e.g. CA, or US for national totals'},offense:{type:'string',description:'One of: violent-crime, homicide, property-crime, robbery, aggravated-assault, burglary, larceny, motor-vehicle-theft, arson'},startYear:{type:'number',description:'First year to include, default 2014'},endYear:{type:'number',description:'Last year to include, default current year'}},required:['state','offense']}}},{type:'function',function:{name:'get_news_data_context',description:'Find which live Calitree news articles are linked to a given crime-data state/offense/year, via deterministic keyword and date matching (no AI guessing). Use this when asked whether any news coverage relates to a specific crime statistic, state, or year.',parameters:{type:'object',properties:{state:{type:'string',description:'Two-letter state code, e.g. CA, or US'},offense:{type:'string',description:'Offense type, e.g. violent-crime, homicide, property-crime'},year:{type:'number',description:'Optional specific year to filter articles and crime data to'},limit:{type:'number',description:'Max matched articles, default 10, max 30'}},required:[]}}}];
async function calitreeAssistantSearch(env,args={}){await schema(env);const limit=Math.min(Number(args.limit||8),30);let rows=[];const kw=String(args.keyword||'').trim();const lane=String(args.lane||'').trim();const stype=String(args.source_type||'').trim();const words=kw.split(/\s+/).filter(Boolean).slice(0,4);try{const clauses=[];const params=[];if(lane){clauses.push('capture_type=?');params.push(lane)}if(stype){clauses.push('source_type=?');params.push(stype)}if(words.length){const wordOr=words.map(()=>'(title LIKE ? OR first_query LIKE ? OR url LIKE ?)').join(' OR ');clauses.push('('+wordOr+')');for(const w of words){const p='%'+w+'%';params.push(p,p,p)}}const where=clauses.length?('WHERE '+clauses.join(' AND ')):'';rows=await all(env.DB,'SELECT title,url,source_type,capture_type,first_query,last_seen_at FROM discovery_index '+where+' ORDER BY last_seen_at DESC LIMIT ?',[...params,limit])}catch(e){rows=[]}return rows||[]}
async function calitreeAssistantTool(env,name,args){if(name==='list_lanes')return{lanes:CALITREE_LANES.map(l=>({key:l[0],label:l[1]}))};if(name==='search_calitree')return{results:await calitreeAssistantSearch(env,args||{})};if(name==='get_metrics'){try{await schema(env);const rows=await all(env.DB,'SELECT metric_key,label,value,unit,period,source FROM calitree_metrics ORDER BY fetched_at DESC LIMIT 10');if(!rows||!rows.length)return{metrics:[],note:'No metrics stored yet - economic metrics need a free FRED API key configured as the FRED_API_KEY secret.'};return{metrics:rows}}catch(e){return{metrics:[],note:'metrics_unavailable'}}}if(name==='search_cannabis_genetics'){try{await schema(env);const sid=String(args.strain_id||'').trim();const sname=String(args.strain_name||'').trim();const lim=Math.max(1,Math.min(Number(args.limit||8),20));if(sid){const strain=await first(env.DB,'SELECT * FROM cannabis_strains WHERE id=?',[sid]);if(!strain)return{error:'strain_not_found',strain_id:sid};const parents=await all(env.DB,'SELECT cs.id,cs.name,cs.type,cs.breeder FROM strain_lineage sl JOIN cannabis_strains cs ON cs.id=sl.parent_id WHERE sl.strain_id=?',[sid]);const children=await all(env.DB,'SELECT cs.id,cs.name,cs.type,cs.breeder FROM strain_lineage sl JOIN cannabis_strains cs ON cs.id=sl.strain_id WHERE sl.parent_id=?',[sid]);const result={strain,parents,children,source:CANNABIS_SOURCE,snapshot_note:'Static 2017 dataset, not live data'};if(args.tree){const ancestry=await all(env.DB,"WITH RECURSIVE anc(id,name,type,breeder,depth) AS (SELECT id,name,type,breeder,0 FROM cannabis_strains WHERE id=? UNION ALL SELECT cs.id,cs.name,cs.type,cs.breeder,anc.depth+1 FROM strain_lineage sl JOIN cannabis_strains cs ON cs.id=sl.parent_id JOIN anc ON anc.id=sl.strain_id WHERE anc.depth<5) SELECT * FROM anc ORDER BY depth,name",[sid]);result.ancestry_tree=ancestry}return result}if(sname){const strains=await all(env.DB,'SELECT id,name,type,breeder,effects,flavor,terpenes,thc,cbd FROM cannabis_strains WHERE name LIKE ? ORDER BY name LIMIT ?',['%'+sname+'%',lim]);return{results:strains,count:strains.length,source:CANNABIS_SOURCE,snapshot_note:'Static 2017 dataset, not live data',hint:strains.length?'Pass strain_id from one of these results to get full detail or lineage.':'No matches - try a shorter or different strain name.'}}return{error:'provide strain_name or strain_id'}}catch(e){return{error:String(e.message||e)}}}if(name==='get_crime_trend'){try{const result=await getCrimeTrends(env,args||{});return result}catch(e){return{error:String(e.message||e)}}}if(name==='get_news_data_context'){try{await schema(env);const state=normalizeCrimeState(args.state||'US')||'US';const offense=normalizeCrimeOffense(args.offense||'violent-crime')||'violent-crime';const year=args.year?Number(args.year):null;const lim=Math.max(1,Math.min(Number(args.limit||10),30));let metricRows=[];if(year){metricRows=await all(env.DB,'SELECT year AS y,state AS s,offense_type AS o,offense_count AS c,population AS p,rate_per_100k AS r FROM fbi_crime_rollups WHERE state=? AND offense_type=? AND year=?',[state,offense,year])}else{metricRows=await all(env.DB,'SELECT year AS y,state AS s,offense_type AS o,offense_count AS c,population AS p,rate_per_100k AS r FROM fbi_crime_rollups WHERE state=? AND offense_type=? ORDER BY year DESC LIMIT 10',[state,offense])}const clauses=['keywords LIKE ?'];const params=['%"'+offense+'"%'];if(year){clauses.push('published_date LIKE ?');params.push(String(year)+'%')}if(state&&state!=='US'){const stateNameMatch=CT_STATES.find(s=>s.toUpperCase().startsWith(state)||s.toUpperCase()===state);if(stateNameMatch){clauses.push('keywords LIKE ?');params.push('%"'+stateNameMatch+'"%')}}const where=clauses.join(' AND ');const articles=await all(env.DB,'SELECT title,url,source_type,published_date FROM discovery_index WHERE '+where+' ORDER BY published_date DESC LIMIT ?',[...params,lim]);return{state,offense,year,crime_data:metricRows,matched_articles:articles,matched_article_count:articles.length,note:'Deterministic SQL/keyword match, not AI-generated correlation.'}}catch(e){return{error:String(e.message||e)}}}return{error:'unknown_tool: '+name}}
async function calitreeAssistantChat(env,args={}){const userMessage=String(args.message||'').slice(0,2000);if(!userMessage)return{ok:false,error:'message required',policy:POLICY};const history=Array.isArray(args.history)?args.history.slice(-8).map(m=>({role:m.role==='assistant'?'assistant':'user',content:String(m.content||'').slice(0,2000)})):[];const sys={role:'system',content:'You are the Calitree Assistant, embedded in a live cannabis news, science, and podcast aggregator. You have five tools: search_calitree for real current articles, list_lanes for categories, get_metrics for economic data, search_cannabis_genetics for the 9,500+ strain lineage database (cannabinoid profiles, breeders, parent/cross ancestry), get_crime_trend for aggregate FBI/CDE crime statistics by state/offense/year, and get_news_data_context to find which live articles relate to a given crime statistic. Always call the relevant tool before answering questions about news, strains, genetics, lineage, crime data, or what is new or related - never invent headlines, strain facts, lineage, or statistics. When discussing crime data, never imply cannabis caused, increased, decreased, or prevented any crime trend - it is general public-safety data, not cannabis-specific. Keep answers short and conversational. Educational and informational only: never give medical, legal, or investment advice, and never recommend cannabis use.'};let messages=[sys,...history,{role:'user',content:userMessage}];const toolLog=[];for(let i=0;i<4;i++){let resp;try{resp=await env.AI.run('@cf/zai-org/glm-4.7-flash',{messages,tools:CALITREE_ASSISTANT_TOOLS})}catch(e){return{ok:false,error:'ai_run_failed: '+(e.message||e),tool_log:toolLog,policy:POLICY}}const choice=resp.choices&&resp.choices[0];const msg=choice&&choice.message||{};const toolCalls=msg.tool_calls||null;const replyText=msg.content||'';if(toolCalls&&toolCalls.length){messages.push({role:'assistant',content:replyText,tool_calls:toolCalls});for(const call of toolCalls){const fname=call.function&&call.function.name||call.name||'';let fargs={};try{const rawArgs=call.function&&call.function.arguments!==undefined?call.function.arguments:call.arguments;fargs=typeof rawArgs==='string'?JSON.parse(rawArgs||'{}'):(rawArgs||{})}catch(e){fargs={}}const result=await calitreeAssistantTool(env,fname,fargs);toolLog.push({tool:fname,args:fargs,result_count:Array.isArray(result.results)?result.results.length:null});messages.push({role:'tool',tool_call_id:call.id||fname,content:JSON.stringify(result).slice(0,4000)})}continue}return{ok:true,reply:replyText||'I could not find anything for that - try rephrasing.',tool_log:toolLog,model:'@cf/zai-org/glm-4.7-flash',policy:POLICY}}return{ok:true,reply:'That took too many lookups - try asking something more specific.',tool_log:toolLog,policy:POLICY}}
async function calitreeIngestSecFilings(env){await schema(env);const today=new Date();const start=new Date(today.getTime()-30*86400000).toISOString().slice(0,10);const end=today.toISOString().slice(0,10);const url='https://efts.sec.gov/LATEST/search-index?q=cannabis&forms=10-K,10-Q,8-K&dateRange=custom&startdt='+start+'&enddt='+end;let upserted=0;const seen=new Set();try{const r=await fetch(url,{headers:{'user-agent':'CalitreeReview/0.1 (research; contact: ops@calitree.example)'}});if(!r.ok)return{ok:false,error:'sec_fetch_failed_'+r.status};const data=await r.json();const hits=(data.hits&&data.hits.hits)||[];for(const h of hits){const s=h._source||{};const adsh=s.adsh;if(!adsh||seen.has(adsh))continue;seen.add(adsh);const cik=String((s.ciks&&s.ciks[0])||'').replace(/^0+/,'');const accNoDash=adsh.replace(/-/g,'');const filename=(h._id||'').split(':')[1]||'';const docUrl=cik&&filename?('https://www.sec.gov/Archives/edgar/data/'+cik+'/'+accNoDash+'/'+filename):('https://www.sec.gov/cgi-bin/browse-edgar?action=getcompany&CIK='+cik);const company=(s.display_names&&s.display_names[0])||'Unknown company';const title=company+' \u2014 '+s.form+' filed '+s.file_date;await upsertIndexItem(env,{url:docUrl,title,source_type:'sec_filing',capture_type:'business_industry',first_query:'cannabis sec filing financial '+s.form+' '+company},'sec_edgar_fts','capture');upserted++}return{ok:true,upserted,total_hits_scanned:hits.length,window:{start,end}}}catch(e){return{ok:false,error:String(e.message||e)}}}
const CALITREE_METRIC_DEFS=[{key:'fred_cpi_all',label:'US Consumer Price Index (all items, broad economic context)',source:'fred',series_id:'CPIAUCSL'},{key:'fred_retail_sales',label:'US Retail Trade Sales (broad economic context)',source:'fred',series_id:'RSXFS'}];
async function calitreeFetchMetrics(env){await schema(env);if(!env.FRED_API_KEY)return{ok:false,configured:false,error:'FRED_API_KEY not set - get a free key at https://fred.stlouisfed.org/docs/api/api_key.html and add it as a Worker secret to enable economic metrics.'};let upserted=0;const results=[];for(const m of CALITREE_METRIC_DEFS){try{const r=await fetch('https://api.stlouisfed.org/fred/series/observations?series_id='+m.series_id+'&api_key='+env.FRED_API_KEY+'&file_type=json&sort_order=desc&limit=1');if(!r.ok){results.push({metric:m.key,ok:false,error:'http_'+r.status});continue}const data=await r.json();const obs=(data.observations||[])[0];if(!obs){results.push({metric:m.key,ok:false,error:'no_observation'});continue}const id='metric_'+m.key+'_'+obs.date;await run(env.DB,'INSERT INTO calitree_metrics (id,metric_key,label,value,unit,period,source,source_url,fetched_at,created_at) VALUES (?,?,?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET value=excluded.value,fetched_at=excluded.fetched_at',[id,m.key,m.label,parseFloat(obs.value)||null,'index_or_billions',obs.date,'fred','https://fred.stlouisfed.org/series/'+m.series_id,nowIso(),nowIso()]);upserted++;results.push({metric:m.key,ok:true,value:obs.value,period:obs.date})}catch(e){results.push({metric:m.key,ok:false,error:String(e.message||e)})}}return{ok:true,configured:true,upserted,results}}
