async function calitreeStoreFbiRaw(env,key,text,meta={}){if(!env.CALITREE_RAW)return{ok:false,skipped:true,error:'CALITREE_RAW R2 binding not configured'};await env.CALITREE_RAW.put(key,text,{httpMetadata:{contentType:'text/csv; charset=utf-8'},customMetadata:{source:'fbi_cde',dataset:FBI_CDE_DATASET_KEY,fetched_at:meta.fetched_at||nowIso(),period:String(meta.period||'')}});return{ok:true,key,bytes:text.length}}
